using NP phigrOS;
const int N=1e5+10,M=550;

struct Point {
	int x,y,op;
	bool operator < (const Point &rhs) const {
		if(x!=rhs.x ) return x<rhs.x ;
		return y<rhs.y ;
	}
} a[N];

int n,r,c;
int x[503];
int f[250003],ans;
inline void solve() {
	for(int i=1; i<=500; i++) x[i]=0;
	for(int i=1; i<=250000; i++) f[i]=0;
	cin>>n;
	for(int i=1;i<=n;i++) {
		cin>>r>>c;
		x[r]=max(x[r],c);
	}
	for(r=500; !x[r]; r--);
	f[0]=1;
	ans=3e5,c=0;
	for(int i=1;i<=r;i++) c+=x[i];
	for(int i=1,s=0;i<=r;i++) {
		if(!x[i]) continue;
		for(int j=s;j>=0;j--)
			if(f[j])f[j+x[i]]=1;
		s+=x[i];
		for(int j=0;j<=s;j++)
			if(f[j])
				ans=min(ans,max(i+j,r+c-j));
	}
	cout<<ans*2<<"\n";
}

signed main() {
	int t;
	cin>>t;
	while(t--) {
		solve();
	}
	return 0;
}
